import { type RefObject, createContext, useContext } from 'react';

/**
 * @internal
 */
export interface ChartTooltipMetadata {
  tooltipRef: RefObject<HTMLDivElement | null> | undefined;
}

/**
 * @internal
 */
export const ChartTooltipMetadataContext = createContext<ChartTooltipMetadata>({
  tooltipRef: undefined,
});

export const useChartTooltipMetadata = () =>
  useContext(ChartTooltipMetadataContext);

ChartTooltipMetadataContext['displayName'] = 'ChartTooltipMetadataContext';
